query:
MATCH ()-[r:CONECTA_A]->()
SET r.costo_trafico = r.distancia * r.estado_trafico
RETURN r.distancia AS Distancia, r.estado_trafico AS Trafico, r.costo_trafico AS Costo_Calculado;

CALL gds.graph.project(
  'grafo_logistica',
  ['Almacen', 'Interseccion', 'PuntoEntrega'],
  {
    CONECTA_A: {
      orientation: 'UNDIRECTED',
      properties: ['distancia', 'tiempo_estimado', 'costo_trafico']
    }
  }
)
YIELD graphName, nodeCount, relationshipCount;

// 1. Le damos a todas las rutas una capacidad base de 30 toneladas
MATCH ()-[r:CONECTA_A]->()
SET r.capacidad_maxima = 30;

// 2. Simulamos que la vía hacia San Félix (desde Cruce Castillito) solo soporta 15 toneladas
WITH 1 AS dummy
MATCH (i:Interseccion {id: 'I3'})-[r:CONECTA_A]->(p:PuntoEntrega {id: 'P2'})
SET r.capacidad_maxima = 15;

// Rastreo de cargas pesadas usando WITH
MATCH (c:Conductor)-[:MANEJA]->(v:Vehiculo)-[:LLEVA]->(ped:Pedido)-[:ENTREGAR_EN]->(destino:PuntoEntrega)
WITH c.nombre AS Chofer, v.placa AS Placa, ped.peso_toneladas AS Carga, destino.nombre AS Cliente
WHERE Carga > 10
RETURN Chofer, Placa, Carga, Cliente
ORDER BY Carga DESC;

// Desglose de listas de pedidos usando UNWIND
WITH ['PED-001', 'PED-002', 'PED-003'] AS lista_pedidos
UNWIND lista_pedidos AS id_pedido
MATCH (p:Pedido {id: id_pedido})<-[:LLEVA]-(v:Vehiculo)<-[:MANEJA]-(c:Conductor)
RETURN id_pedido AS Codigo_Pedido, p.prioridad AS Prioridad, c.nombre AS Responsable, v.tipo AS Tipo_Camion
ORDER BY Prioridad;

MATCH ruta = (origen:Almacen {id: 'A1'})-[conexiones:CONECTA_A*1..5]-(destino:PuntoEntrega {id: 'P3'})
WHERE ALL(tramo IN conexiones WHERE tramo.capacidad_maxima >= 15)
RETURN ruta LIMIT 1;

//Algoritmo Dijkstra basado en tráfico
MATCH (origen:Almacen {id: 'A1'}), (destino:PuntoEntrega {id: 'P2'})
CALL gds.shortestPath.dijkstra.stream('grafo_logistica', {
    sourceNode: origen,
    targetNode: destino,
    relationshipWeightProperty: 'costo_trafico'
})
YIELD totalCost, nodeIds
RETURN origen.nombre AS Salida,
       destino.nombre AS Llegada,
       totalCost AS Costo_Tiempo_Trafico,
       [n IN nodeIds | gds.util.asNode(n).nombre] AS Trayecto_Sugerido;

MATCH (origen:Almacen {id: 'A1'}), (destino:PuntoEntrega {id: 'P2'})
CALL gds.shortestPath.dijkstra.stream('grafo_logistica', {
    sourceNode: origen,
    targetNode: destino,
    relationshipWeightProperty: 'costo_trafico'
})
YIELD path
RETURN path;

// Resumen operativo usando subconsultas
MATCH (a:Almacen)
CALL (a) {
    MATCH (v:Vehiculo)-[:UBICADO_EN]->(a)
    RETURN count(v) AS total_vehiculos, sum(v.capacidad_toneladas) AS capacidad_flota
}
RETURN a.nombre AS Centro_Logistico, total_vehiculos AS Vehiculos_Disponibles, capacidad_flota AS Toneladas_Totales;

// Resumen operativo usando subconsultas
MATCH (a:Almacen)
CALL {
    WITH a
    MATCH (v:Vehiculo)-[:UBICADO_EN]->(a)
    RETURN count(v) AS total_vehiculos, sum(v.capacidad_toneladas) AS capacidad_flota
}
RETURN a.nombre AS Centro_Logistico, total_vehiculos AS Vehiculos_Disponibles, capacidad_flota AS Toneladas_Totales;

MATCH (a:Almacen)
CALL (a) {
    MATCH (v:Vehiculo)-[r:UBICADO_EN]->(a)
    RETURN v, r
}
RETURN a, v, r;
